// Get all post history items
const allPosts = $('Get Post History').all();
const allMedia = $('Get Media Catalog').all();

// Calculate date range (last 7 days)
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Filter posts from last 7 days
const weekPosts = allPosts.filter(p => {
  const publishedAt = new Date(p.json.published_at);
  return publishedAt >= weekAgo;
});

// === FANVUE STATS ===
const fanvuePosts = weekPosts.filter(p => p.json.caption_source !== 'social_media_blotato');
const remainingFanvue = allMedia.filter(m => m.json.source_folder === 'nsfw' && m.json.added_to_fanvue === false).length;

const totalPosts = fanvuePosts.length;
const imagePosts = fanvuePosts.filter(p => p.json.media_type === 'image').length;
const videoPosts = fanvuePosts.filter(p => p.json.media_type === 'video').length;
const ppvPosts = fanvuePosts.filter(p => p.json.ppv_price > 0);
const ppvCount = ppvPosts.length;
const ppvRevenuePotential = ppvPosts.reduce((sum, p) => sum + (parseFloat(p.json.ppv_price) || 0), 0);
const aiCaptions = fanvuePosts.filter(p => p.json.caption_source === 'ai-live').length;
const preGenCaptions = fanvuePosts.filter(p => p.json.caption_source === 'pre-generated').length;

// Fanvue posts per day breakdown
const dayNames = ['Nd', 'Pn', 'Wt', 'Sr', 'Cz', 'Pt', 'Sb'];
const postsByDay = {};
for (const p of fanvuePosts) {
  const d = new Date(p.json.published_at);
  const dayKey = `${dayNames[d.getDay()]} ${d.getDate()}.${(d.getMonth()+1).toString().padStart(2,'0')}`;
  postsByDay[dayKey] = (postsByDay[dayKey] || 0) + 1;
}

let dayBreakdownHtml = '';
for (const [day, count] of Object.entries(postsByDay)) {
  dayBreakdownHtml += `<tr><td style="padding: 6px 12px; border: 1px solid #ddd;">${day}</td><td style="padding: 6px 12px; border: 1px solid #ddd; text-align: center;">${count}</td></tr>`;
}

// Fanvue recent posts (last 5)
const recentPosts = fanvuePosts
  .sort((a, b) => new Date(b.json.published_at) - new Date(a.json.published_at))
  .slice(0, 5);

let recentPostsHtml = '';
for (const p of recentPosts) {
  const d = new Date(p.json.published_at);
  const dateStr = d.toLocaleDateString('pl-PL');
  const ppvLabel = p.json.ppv_price > 0 ? `PPV $${p.json.ppv_price}` : 'FREE';
  const caption = (p.json.caption || '').substring(0, 80);
  recentPostsHtml += `<tr><td style="padding: 6px; border: 1px solid #ddd; font-size: 12px;">${dateStr}</td><td style="padding: 6px; border: 1px solid #ddd; font-size: 12px;">${p.json.file_name || '-'}</td><td style="padding: 6px; border: 1px solid #ddd; font-size: 12px;">${ppvLabel}</td><td style="padding: 6px; border: 1px solid #ddd; font-size: 12px;">${caption}...</td></tr>`;
}

// Fanvue days until empty
const avgFanvuePerDay = totalPosts > 0 ? totalPosts / 7 : 2;
const fanvueDaysUntilEmpty = avgFanvuePerDay > 0 ? Math.floor(remainingFanvue / avgFanvuePerDay) : 999;

// === SOCIAL MEDIA STATS ===
const smPosts = weekPosts.filter(p => p.json.caption_source === 'social_media_blotato');
const smTotal = smPosts.length;
const smImages = smPosts.filter(p => (p.json.media_type || '').includes('image')).length;
const smVideos = smPosts.filter(p => (p.json.media_type || '').includes('video')).length;
const remainingSocialMedia = allMedia.filter(m => m.json.source_folder === 'socialmedia' && m.json.added_to_social_media === false).length;

// Social media posts per day
const smByDay = {};
for (const p of smPosts) {
  const d = new Date(p.json.published_at);
  const dayKey = `${dayNames[d.getDay()]} ${d.getDate()}.${(d.getMonth()+1).toString().padStart(2,'0')}`;
  smByDay[dayKey] = (smByDay[dayKey] || 0) + 1;
}

let smDayBreakdownHtml = '';
for (const [day, count] of Object.entries(smByDay)) {
  smDayBreakdownHtml += `<tr><td style="padding: 6px 12px; border: 1px solid #ddd;">${day}</td><td style="padding: 6px 12px; border: 1px solid #ddd; text-align: center;">${count}</td></tr>`;
}

// Social media recent posts (last 5)
const smRecent = smPosts
  .sort((a, b) => new Date(b.json.published_at) - new Date(a.json.published_at))
  .slice(0, 5);

let smRecentHtml = '';
for (const p of smRecent) {
  const d = new Date(p.json.published_at);
  const dateStr = d.toLocaleDateString('pl-PL');
  const type = (p.json.media_type || 'image');
  const caption = (p.json.caption || '').substring(0, 80);
  smRecentHtml += `<tr><td style="padding: 6px; border: 1px solid #ddd; font-size: 12px;">${dateStr}</td><td style="padding: 6px; border: 1px solid #ddd; font-size: 12px;">${p.json.file_name || '-'}</td><td style="padding: 6px; border: 1px solid #ddd; font-size: 12px;">${type}</td><td style="padding: 6px; border: 1px solid #ddd; font-size: 12px;">${caption}...</td></tr>`;
}

// Social media days until empty
const avgSmPerDay = smTotal > 0 ? smTotal / 7 : 1;
const smDaysUntilEmpty = avgSmPerDay > 0 ? Math.floor(remainingSocialMedia / avgSmPerDay) : 999;

// Content warnings
const fanvueWarning = remainingFanvue < 10
  ? `<div style="margin-top: 12px; padding: 12px; background: #ffcccc; border: 2px solid #cc0000; border-radius: 8px; text-align: center;"><strong style="color: #cc0000;">UWAGA: Fanvue - pozostalo tylko ${remainingFanvue} plikow! Dodaj wiecej contentu do Dropbox.</strong></div>`
  : '';
const smWarning = remainingSocialMedia < 10
  ? `<div style="margin-top: 12px; padding: 12px; background: #ffcccc; border: 2px solid #cc0000; border-radius: 8px; text-align: center;"><strong style="color: #cc0000;">UWAGA: Social Media - pozostalo tylko ${remainingSocialMedia} plikow! Dodaj wiecej contentu do Dropbox.</strong></div>`
  : '';

return [{
  json: {
    // Fanvue
    totalPosts,
    imagePosts,
    videoPosts,
    ppvCount,
    ppvRevenuePotential: ppvRevenuePotential.toFixed(2),
    aiCaptions,
    preGenCaptions,
    remainingFanvue,
    fanvueDaysUntilEmpty,
    dayBreakdownHtml,
    recentPostsHtml,
    // Social Media
    smTotal,
    smImages,
    smVideos,
    remainingSocialMedia,
    smDaysUntilEmpty,
    smDayBreakdownHtml,
    smRecentHtml,
    // General
    totalMedia: allMedia.length,
    contentWarning: fanvueWarning + smWarning,
    weekStart: weekAgo.toLocaleDateString('pl-PL'),
    weekEnd: now.toLocaleDateString('pl-PL')
  }
}];
